path = var_call_gBcuVPsDrl85kNFMJoAUQAxE
articles = json.load(open(path,'r'))
dfa = pd.DataFrame(articles)
# find best matching article for pricing rules
text = (dfa.get('title','').fillna('') + ' ' + dfa.get('summary','').fillna('') + ' ' + dfa.get('faq_answer__c','').fillna('')).str.lower()
keywords = ['discount','unit price','list price','pricebook','pricing','quote line']
